body:
@igorosky, running this sv-test/icarus/ivtest/ivltests/sqrt32.v fails due to #6932.  There's also two UVM failures but I suspect they are related.  I had tested UVM when you first submitted #6932 and it passed, but I didn't think to rerun with your recent changes.

If you think this will take more than a few days to fix we should probably back out #6932.

<details><summary>Code</summary>
```
module sqrt (
    input clk,
    output wire rdy,
    input reset,
    input [31:0] x,
    output reg [15:0] acc
);
  parameter ss = 5;
  localparam w = 1 << ss;
  reg [w-1:0] acc2;
  reg [ss-1:0] bitl;
  wire [w/2-1:0] bbit = 1 << bitl;
  wire [w-1:0] bit2 = 1 << (bitl << 1);
  assign rdy = bitl[ss-1];
  wire [w/2-1:0] guess = acc | bbit;
  wire [w-1:0] guess2 = acc2 + bit2 + ((acc << bitl) << 1);
  (* ivl_synthesis_on *)
  always @(posedge clk or posedge reset)
    if (reset) begin
      acc = 0;
      acc2 = 0;
      bitl = w / 2 - 1;
    end
    else begin
      if (guess2 <= x) begin
        acc <= guess;
        acc2 <= guess2;
      end
      bitl <= bitl - 1;
    end
endmodule
module testBench;
  parameter ss = 5;
  parameter w = 1 << ss;
  parameter Amax = 10001;
  reg [w-1:0] A;
  reg clk, reset;
  wire [(w/2)-1:0] Z;
  wire done;
  sqrt dut (
      .clk(clk),
      .rdy(done),
      .reset(reset),
      .x(A),
      .acc(Z)
  );
  always #5 clk = !clk;
  task reset_dut;
    reset = 1;
    @(posedge clk);
    #1 reset = 0;
    @(negedge clk);
  endtask
  task run_dut;
    while (done == 0) begin
      @(posedge clk);
    end
  endtask
  integer idx, a, z, errCnt;
  initial begin
    reset = 0;
    clk = 0;
    $display("ss=%d, width=%d, Amax=%d", ss, w, Amax);
    errCnt = 0;
    A = 4;
    reset_dut;
    run_dut;
    $display("test=0 x=%d, y=%d", A, Z);
    A = Amax / 10;
    reset_dut;
    run_dut;
    $display("test=0 x=%d, y=%d", A, Z);
    A = Amax - 1;
    reset_dut;
    run_dut;
    $display("test=0 x=%d, y=%d", A, Z);
    for (idx = 1; idx < Amax; idx = 2 * idx) begin
      A = idx;
      reset_dut;
      run_dut;
      $display("%d: x=%d, y=%d", idx, A, Z);
      a = A;
      z = Z;
      if (a < (z * z)) begin
        $display("test=%d x=%d, y=%d ERROR:y is too big", idx, A, Z);
        $finish;
      end
      if (z < 65535) begin
        if (a >= ((z + 1) * (z + 1))) begin
          $display("test=%d x=%d, y=%d ERROR: y is too small", idx, A, Z);
          $finish;
        end
      end
      else begin
        $display("Could not verify above number");
      end
    end
    $display("Running  tests Amax=%d random input numbers", Amax);
    for (idx = 0; idx < Amax; idx = 1 + idx) begin
      A = $random;
      if (A < 1 << (w - 1)) begin
        reset_dut;
        run_dut;
        a = A;
        z = Z;
        if (a < (z * z)) begin
          $display("test=%d x=%d, y=%d ERROR:y is too big", idx, A, Z);
          $finish;
        end
        if (z < 65535) begin
          if (a >= ((z + 1) * (z + 1))) begin
            $display("test=%d x=%d, y=%d ERROR: y is too small", idx, A, Z);
            $finish;
          end
        end
        else begin
          $display("Could not verify above number");
        end
        if (idx % 1000 == 0) $display("Finished %d tests", idx);
      end
    end
    $display("PASSED");
    $finish;
  end
endmodule

